class Solution:
    def candy(self, ratings):
        n = len(ratings)
        candy = [1] * n
        changed = True
        while changed:
            changed = False
            for i in range(n):
                if i > 0 and ratings[i] > ratings[i-1] and candy[i] <= candy[i-1]:
                    candy[i] = candy[i-1] + 1
                    changed = True
                if i < n - 1 and ratings[i] > ratings[i+1] and candy[i] <= candy[i+1]:
                    candy[i] = candy[i+1] + 1
                    changed = True
        return sum(candy)

